// Neon River -- warm pinks and teals, heavy modulation, hue drift feedback
speed = 0.5

AUDIO.bins = 6; AUDIO.smooth = 0.80; AUDIO.gain = 30; AUDIO.apply();
var _lo = function(){ return a.fft[0] || 0 };
var _mi = function(){ return a.fft[2] || 0 };
var _hi = function(){ return a.fft[4] || 0 };
var low  = env(_lo, 0.4, 0.03);
var mid  = env(_mi, 0.35, 0.04);
var high = env(_hi, 0.3, 0.05);
var amp  = function(){ return (low() + mid() + high()) * 0.7 };

osc(12, 0.04, 2.2)
  .color(
    () => 1.0 + low() * 0.4,
    () => 0.3 + mid() * 0.3,
    () => 0.7 + high() * 0.5
  )
  .rotate(() => time * 0.02)
  .blend(
    osc(8, -0.03, 1.5)
      .color(
        () => 0.4 + high() * 0.3,
        () => 0.8 + mid() * 0.4,
        () => 0.9 + low() * 0.3
      )
      .rotate(() => time * -0.015),
    0.45
  )
  .modulate(noise(3, 0.2), () => 0.12 + low() * 0.01)
  .modulate(noise(1.5, 0.08), () => 0.04 + mid() * 0.006)
  .blend(src(o0).rotate(() => Math.sin(time * 0.025) * 0.004).hue(() => amp() * 0.008), 0.82)
  .saturate(() => 1.3 + low() * 0.3)
  .colorama(() => 0.002 + amp() * 0.004)
  .hue(() => Math.sin(time * 0.06) * 0.02 + mid() * 0.01)
  .contrast(() => 1.03 + low() * 0.06)
  .brightness(0.03)
  .out(o0)
